import network
import socket
import ustruct as struct
import ubinascii
import ujson
import time
from machine import Pin

# WiFi configuration
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# Initialize LED pin
led = Pin(2, Pin.OUT)

# WiFi connection
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(WIFI_SSID, WIFI_PASSWORD)
    
    while not wlan.isconnected():
        time.sleep(1)
    
    print("Connected to WiFi")
    print("IP address:", wlan.ifconfig()[0])

# WebSocket server
class WebSocketServer:
    def __init__(self):
        self.clients = []
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', 80))
        self.sock.listen(5)
        
    def handshake(self, client_socket):
        # Simple WebSocket handshake
        request = client_socket.recv(1024).decode()
        
        if "Upgrade: websocket" in request:
            # Extract Sec-WebSocket-Key
            key = request.split("Sec-WebSocket-Key: ")[1].split("\r\n")[0]
            
            # Generate WebSocket accept key
            accept_key = ubinascii.b2a_base64(
                ubinascii.sha1(key.encode() + b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11")
            ).decode().strip()
            
            # Send handshake response
            response = (
                "HTTP/1.1 101 Switching Protocols\r\n"
                "Upgrade: websocket\r\n"
                "Connection: Upgrade\r\n"
                "Sec-WebSocket-Accept: " + accept_key + "\r\n\r\n"
            )
            
            client_socket.send(response.encode())
            return True
        return False
    
    def receive_message(self, client_socket):
        try:
            data = client_socket.recv(1024)
            if not data:
                return None
                
            # Parse WebSocket frame
            if len(data) < 2:
                return None
                
            # Check if it's a text frame
            opcode = data[0] & 0x0F
            if opcode != 1:  # Text frame
                return None
                
            # Get payload length
            payload_len = data[1] & 0x7F
            if payload_len == 126:
                payload_len = struct.unpack('>H', data[2:4])[0]
                mask_offset = 4
            elif payload_len == 127:
                payload_len = struct.unpack('>Q', data[2:10])[0]
                mask_offset = 10
            else:
                mask_offset = 2
                
            # Extract mask
            mask = data[mask_offset:mask_offset+4]
            payload_offset = mask_offset + 4
            
            # Decode payload
            payload = data[payload_offset:payload_offset+payload_len]
            
            # Apply mask
            decoded = bytearray()
            for i in range(len(payload)):
                decoded.append(payload[i] ^ mask[i % 4])
                
            return decoded.decode('utf-8')
        except Exception as e:
            return None
    
    def send_message(self, client_socket, message):
        try:
            # Create WebSocket frame
            message_bytes = message.encode('utf-8')
            length = len(message_bytes)
            
            frame = bytearray()
            frame.append(0x81)  # Text frame
            
            if length <= 125:
                frame.append(length)
            elif length <= 65535:
                frame.append(126)
                frame.extend(struct.pack('>H', length))
            else:
                frame.append(127)
                frame.extend(struct.pack('>Q', length))
                
            frame.extend(message_bytes)
            client_socket.send(frame)
        except Exception as e:
            pass
    
    def handle_client(self, client_socket):
        if not self.handshake(client_socket):
            client_socket.close()
            return
            
        self.clients.append(client_socket)
        print("New client connected")
        
        while True:
            try:
                message = self.receive_message(client_socket)
                if message:
                    try:
                        data = ujson.loads(message)
                        print("Received:", data)
                        
                        # Handle commands
                        if "action" in data:
                            if data["action"] == "turn_on":
                                led.on()
                                response = {"status": "turned_on"}
                            elif data["action"] == "turn_off":
                                led.off()
                                response = {"status": "turned_off"}
                            else:
                                response = {"status": "unknown_action"}
                        else:
                            response = {"status": "no_action"}
                            
                        self.send_message(client_socket, ujson.dumps(response))
                        
                    except Exception as e:
                        print("Error parsing JSON:", e)
                        self.send_message(client_socket, ujson.dumps({"error": "invalid_json"}))
                else:
                    # Client disconnected
                    self.clients.remove(client_socket)
                    client_socket.close()
                    print("Client disconnected")
                    break
                    
            except Exception as e:
                print("Client error:", e)
                self.clients.remove(client_socket)
                client_socket.close()
                break
    
    def start(self):
        print("WebSocket server starting on port 80")
        while True:
            try:
                client_socket, addr = self.sock.accept()
                print("Connection from:", addr)
                # Handle each client in a separate task (simple approach)
                self.handle_client(client_socket)
            except Exception as e:
                print("Server error:", e)
                time.sleep(1)

# Main execution
connect_wifi()
server = WebSocketServer()
server.start()